Here is the fully deobfuscated and cleaned-up version of the code, followed by a detailed explanation of how it works.

### The Deobfuscated Code

```javascript
// --- CONFIGURATION ---
const config = {
    repulsion: 4000,      // How strongly nodes push each other away
    springK: 0.004,       // Default spring stiffness
    damping: 0.92,        // Friction/Air resistance
    gravity: 0.0003,      // Pull towards the center of the screen
    particleMax: 40,      // Maximum number of visual particles
    particleFade: 0.04,   // How fast particles fade out
    cameraEase: 0.06      // Camera smoothing speed (Lerp)
};

// --- DATA STRUCTURES ---

// Nodes (The vertices of the graph)
const nodes = [
    { id: 'Hub',     label: 'Hub',     r: 26, x: 400, y: 300, vx: 0, vy: 0 },
    { id: 'alpha',   label: 'alpha',   r: 16, x: 500, y: 200, vx: 0, vy: 0 },
    { id: 'beta',    label: 'beta',    r: 16, x: 300, y: 400, vx: 0, vy: 0 },
    { id: 'gamma',   label: 'gamma',   r: 14, x: 250, y: 180, vx: 0, vy: 0 },
    { id: 'delta',   label: 'delta',   r: 14, x: 550, y: 380, vx: 0, vy: 0 },
    { id: 'epsilon', label: 'epsilon', r: 12, x: 350, y: 150, vx: 0, vy: 0 }
];

// Links (The springs connecting the nodes)
const links = [
    { a: 'Hub',   b: 'alpha',   rest: 160, k: 0.006 },
    { a: 'Hub',   b: 'beta',    rest: 160, k: 0.005 },
    { a: 'Hub',   b: 'gamma',   rest: 170, k: 0.004 },
    { a: 'Hub',   b: 'delta',   rest: 170, k: 0.004 },
    { a: 'Hub',   b: 'epsilon', rest: 180, k: 0.003 },
    { a: 'alpha', b: 'beta',    rest: 200, k: 0.002 },
    { a: 'gamma', b: 'delta',   rest: 220, k: 0.002 },
    { a: 'alpha', b: 'epsilon', rest: 200, k: 0.002 }
];

// Camera state and target
let camera = { x: 400, y: 300, zoom: 1 };
let targetCamera = { x: 400, y: 300, zoom: 1 };

let particles = [];
let tickCount = 0;

// Helper to find a node by its ID
function getNodeById(id) {
    return nodes.find(node => node.id === id) || null;
}

// --- CORE SYSTEMS ---

// 1. PHYSICS ENGINE
function updatePhysics() {
    // Apply Repulsion (Nodes pushing away from each other)
    for (let i = 0; i < nodes.length; i++) {
        for (let j = i + 1; j < nodes.length; j++) {
            let dx = nodes[i].x - nodes[j].x;
            let dy = nodes[i].y - nodes[j].y;
            let distSq = (dx * dx + dy * dy) || 1;
            let distance = Math.sqrt(distSq);

            // Force is inversely proportional to distance squared
            let force = config.repulsion / distSq;
            let fx = (dx / distance) * force;
            let fy = (dy / distance) * force;

            nodes[i].vx += fx;
            nodes[i].vy += fy;
            nodes[j].vx -= fx;
            nodes[j].vy -= fy;
        }
    }

    // Apply Spring Forces (Links pulling nodes together)
    for (let i = 0; i < links.length; i++) {
        let nodeA = getNodeById(links[i].a);
        let nodeB = getNodeById(links[i].b);
        if (!nodeA || !nodeB) continue;

        let dx = nodeB.x - nodeA.x;
        let dy = nodeB.y - nodeA.y;
        let distance = Math.sqrt(dx * dx + dy * dy) || 1;

        // Hooke's Law: Force = stiffness * displacement from rest length
        let displacement = distance - links[i].rest;
        let force = (links[i].k || config.springK) * displacement;

        let fx = (dx / distance) * force;
        let fy = (dy / distance) * force;

        nodeA.vx += fx;
        nodeA.vy += fy;
        nodeB.vx -= fx;
        nodeB.vy -= fy;
    }

    // Apply Gravity, Damping (Friction), and Update Positions
    for (let i = 0; i < nodes.length; i++) {
        let node = nodes[i];

        // Gravity pulling slightly towards center (x: 400, y: 300)
        node.vx += (400 - node.x) * config.gravity;
        node.vy += (300 - node.y) * config.gravity;

        // Friction
        node.vx *= config.damping;
        node.vy *= config.damping;

        // Apply velocity to position
        node.x += node.vx;
        node.y += node.vy;
    }
}

// 2. PARTICLE EMITTER
function emitParticle() {
    if (particles.length >= config.particleMax) return;

    // Pick a random node to emit a particle from
    let randomNode = nodes[Math.floor(Math.random() * nodes.length)];
    let angle = Math.random() * (Math.PI * 2);
    let speed = 0.3 + Math.random() * 0.7;

    particles.push({
        x: randomNode.x,
        y: randomNode.y,
        vx: Math.cos(angle) * speed,
        vy: Math.sin(angle) * speed,
        age: 0,
        maxAge: 800 + (Math.random() * 1200),
        size: 0.8 + (Math.random() * 1.2)
    });
}

// 3. PARTICLE UPDATER
function updateParticles() {
    // Loop backwards so we can safely splice (remove) dead particles
    for (let i = particles.length - 1; i >= 0; i--) {
        let p = particles[i];
        p.age++;

        // Apply friction to particles
        p.vx *= 0.995;
        p.vy *= 0.995;

        // Update position
        p.x += p.vx;
        p.y += p.vy;

        // Remove if too old
        if (p.age > p.maxAge) {
            particles.splice(i, 1);
        }
    }
}

// 4. CAMERA UPDATER
function updateCamera() {
    // Linear Interpolation (Lerp) to smoothly follow a target
    camera.x += (targetCamera.x - camera.x) * config.cameraEase;
    camera.y += (targetCamera.y - camera.y) * config.cameraEase;
    camera.zoom += (targetCamera.zoom - camera.zoom) * config.cameraEase;
}

// --- MAIN LOOP ---
function mainLoop() {
    updatePhysics();
    updateCamera();
    updateParticles();

    // Emit a particle every 3rd tick
    if (tickCount % 3 === 0) {
        emitParticle();
    }

    tickCount++;
}

// Run the main loop every 16ms (approx 60 Frames Per Second)
setInterval(mainLoop, 16);
```

### Explanation of What It Does

This script creates the mathematical foundation for a visual simulation. Here's a breakdown of its features:

1. **Force-Directed Graph (Physics):**
   It has an array of `nodes` (named Hub, alpha, beta, etc.) and an array of `links` (springs) that connect them.
   * **Repulsion:** It uses a mathematical formula similar to Coulomb's Law to make sure all nodes push each other away so they don't overlap.
   * **Springs:** It uses Hooke's Law to calculate how nodes pull each other together if they are connected by a link.
   * **Gravity & Damping:** It gently pulls the entire cluster toward the center of the screen `(400, 300)` and applies friction so the nodes eventually settle into a stable shape instead of bouncing infinitely.

2. **Particle System:**
   Every 3 ticks (roughly 20 times a second), it picks a random node and spawns a "particle" from it. These particles float outwards with their own velocity, slow down over time due to friction, and eventually die (are deleted) when they reach their `maxAge`.

3. **Smooth Camera:**
   It tracks a camera `x, y, and zoom` using a technique called *Lerp* (Linear Interpolation). This means if the target moves, the camera fluidly glides to catch up rather than snapping instantly.

### Note on Execution
While this script handles all the math and data logic, **it doesn't actually draw anything to the screen.** In its original context, there is undoubtedly another part of the code (likely using `requestAnimationFrame` and an HTML5 `<canvas>` Context) that reads the `x` and `y` coordinates of these `nodes` and `particles` to draw lines, circles, and glowing dots on a webpage.
